import {
  Avatar,
  AvatarFallback,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Progress,
} from "@cooud-ui/ui";
import { Star, StarHalf } from "lucide-react";

function ReviewStars({ rating, label }: { rating: number; label: string }) {
  return (
    <span className="flex items-center gap-0.5" role="img" aria-label={label}>
      {[1, 2, 3, 4, 5].map((star) => {
        if (star <= rating) {
          return (
            <Star key={star} className="size-3.5 fill-warning text-warning" aria-hidden="true" />
          );
        }
        if (star - rating <= 0.5) {
          return (
            <StarHalf
              key={star}
              className="size-3.5 fill-warning text-warning"
              aria-hidden="true"
            />
          );
        }
        return <Star key={star} className="size-3.5 text-fg-tertiary" aria-hidden="true" />;
      })}
    </span>
  );
}

interface RatingBar {
  stars: string;
  percent: number;
  label: string;
}

const ratingBars: RatingBar[] = [
  { stars: "5", percent: 82, label: "5 stars: 82% of reviews" },
  { stars: "4", percent: 11, label: "4 stars: 11% of reviews" },
  { stars: "3", percent: 4, label: "3 stars: 4% of reviews" },
  { stars: "2", percent: 2, label: "2 stars: 2% of reviews" },
  { stars: "1", percent: 1, label: "1 star: 1% of reviews" },
];

interface CustomerReview {
  id: string;
  name: string;
  initials: string;
  date: string;
  rating: number;
  ratingLabel: string;
  title: string;
  body: string;
  verified: boolean;
}

const topReviews: CustomerReview[] = [
  {
    id: "sofia",
    name: "Sofia Almeida",
    initials: "SA",
    date: "Jul 2, 2026",
    rating: 5,
    ratingLabel: "Rated 5 out of 5 stars",
    title: "Best headphones I have ever owned",
    body: "The noise cancellation is unreal on flights — I forgot I was seated by the engine. And 40 hours of battery is not marketing math; I charge them about once a week.",
    verified: true,
  },
  {
    id: "marcus",
    name: "Marcus Chen",
    initials: "MC",
    date: "Jun 27, 2026",
    rating: 5,
    ratingLabel: "Rated 5 out of 5 stars",
    title: "Worth every dollar",
    body: "Swapped from a much pricier pair and the Aurora sounds warmer and fits better. Multipoint pairing between my laptop and phone just works.",
    verified: true,
  },
  {
    id: "priya",
    name: "Priya Nair",
    initials: "PN",
    date: "Jun 19, 2026",
    rating: 4,
    ratingLabel: "Rated 4 out of 5 stars",
    title: "Great sound, snug fit at first",
    body: "Sound stage is stunning for the price. The clamp was tight the first week but broke in nicely — would still buy again.",
    verified: false,
  },
];

export function ReviewsSummaryBlock() {
  return (
    <section
      aria-label="Customer reviews"
      className="mx-auto grid w-full max-w-4xl gap-6 lg:grid-cols-[300px_1fr]"
    >
      {/* Aggregate rating */}
      <Card className="h-fit gap-0 shadow-md">
        <CardHeader>
          <CardTitle className="font-display text-lg">Customer reviews</CardTitle>
        </CardHeader>
        <CardContent className="flex flex-col gap-4 pt-2">
          <div className="flex items-end gap-3">
            <span className="font-display text-5xl font-semibold text-fg">4.8</span>
            <div className="flex flex-col gap-1 pb-1">
              <ReviewStars rating={4.8} label="4.8 out of 5 stars" />
              <span className="text-xs text-fg-tertiary">Based on 1,284 reviews</span>
            </div>
          </div>
          <div className="flex flex-col gap-2">
            {ratingBars.map((bar) => (
              <div key={bar.stars} className="flex items-center gap-3">
                <span className="w-3 text-sm text-fg-secondary">{bar.stars}</span>
                <Star className="size-3.5 fill-warning text-warning" aria-hidden="true" />
                <Progress value={bar.percent} aria-label={bar.label} className="flex-1" />
                <span className="w-9 text-end text-sm text-fg-tertiary">{bar.percent}%</span>
              </div>
            ))}
          </div>
          <Button variant="outline" className="w-full">
            Write a review
          </Button>
        </CardContent>
      </Card>

      {/* Top reviews */}
      <div className="flex flex-col gap-4">
        {topReviews.map((review) => (
          <Card key={review.id} className="gap-0 shadow-sm">
            <CardContent className="flex flex-col gap-3">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <div className="flex items-center gap-3">
                  <Avatar>
                    <AvatarFallback>{review.initials}</AvatarFallback>
                  </Avatar>
                  <div className="flex flex-col">
                    <span className="text-sm font-medium text-fg">{review.name}</span>
                    <span className="text-xs text-fg-tertiary">{review.date}</span>
                  </div>
                </div>
                {review.verified ? <Badge variant="success">Verified purchase</Badge> : null}
              </div>
              <div className="flex flex-col gap-1">
                <ReviewStars rating={review.rating} label={review.ratingLabel} />
                <span className="text-sm font-medium text-fg">{review.title}</span>
              </div>
              <p className="text-sm leading-relaxed text-fg-secondary">{review.body}</p>
            </CardContent>
          </Card>
        ))}
      </div>
    </section>
  );
}
